<template>
  <div class="container">
    <img
      src="../assets/small-bg.jpeg"
      alt=""
      class="bg"
    />
    <div class="code-box">
      <h2>HTTISHERE Widgets</h2>
      <div class="inner">
        <input
          type="text"
          class="input-code"
          v-model="code"
          placeholder="请输入访问口令"
        />
        <div class="code-btn" @click="checkCode">
          <i class="el-icon-right" color="#ffffff"></i>
        </div>
      </div>
      <br>
      <p class="msg">口令区分大小写</p>
      <p class="msg">
        该组件库的<strong>访问口令不时会更新</strong>，若口令过期可私信📧
      </p>
      <br>
      <p class="msg">
        小红书：<a href="">@肥汪卷</a> ｜ B站：<a href="">@阿汪同学</a>
      </p>
    </div>
  </div>
</template>
<script>
import md5 from "js-md5";
export default {
  data() {
    return {
      code: "",
    };
  },
  mounted() {},
  methods: {
    checkCode() {
      const _this = this;
      if (!this.code)
        return this.$message({
          message: "请输入正确的访问口令",
          center: true,
          type: "error",
        });
      if (md5(this.code) === this.$token) {
        this.$message({ message: "访问成功", center: true, type: "success" });
        localStorage.setItem('token', md5(this.code))
        setTimeout(function () {
          _this.$router.push({name: "home"});
        }, 2000);
      } else {
        return this.$message({
          message: "口令错误",
          center: true,
          type: "error",
        });
      }
    },
  },
};
</script>
